  "contents": [
    {
      "parts": [
        { "text": "Extract all the information from this police report to match the following JSON schema strictly. The 'client' is the plaintiff or the injured party (e.g. pedestrian, innocent driver). The 'defendant' is the party at fault. Return nothing but the raw JSON object representation. Schema: {\"client_first_name\": \"string\", \"client_last_name\": \"string\", \"defendant_first_name\": \"string\", \"defendant_last_name\": \"string\", \"accident_date\": \"YYYY-MM-DD\", \"accident_location\": \"string\", \"client_plate\": \"string\", \"client_pronoun\": \"he/she/they\", \"num_injured\": 0, \"has_injuries\": true, \"accident_description\": \"string\"}" },
        {
          "inlineData": {
            "mimeType": "application/pdf",
            "data": ["body"]["pdf_base64"]
          }
        }
      ]
    }
  ],
  "generationConfig": {
    "responseMimeType": "application/json"
  }
}) }}

parameters.jsCode:
// Parse Gemini response
const response = .item.json;
let content;
try {
  content = response.candidates[0].content.parts[0].text;
} catch (e) {
  return { json: { error: 'Failed to read Gemini response', raw: JSON.stringify(response).substring(0, 500) } };
}

let extracted;
try {
  let jsonStr = content.replace(/`json\n?/g, '').replace(/`\n?/g, '').trim();
  extracted = JSON.parse(jsonStr);
} catch (e) {
  return { json: { error: 'Failed to parse JSON', raw: content } };
}

const currentMonth = new Date().getMonth() + 1;
let bookingLink, consultationType;
if (currentMonth >= 3 && currentMonth <= 8) {
  bookingLink = 'https://calendly.com/swans-santiago-p/summer-spring';
  consultationType = 'in-office consultation';
} else {
  bookingLink = 'https://calendly.com/swans-santiago-p/winter-autumn';
  consultationType = 'virtual consultation';
}

let accidentSummary = extracted.has_injuries
  ? 'Based on the police report, injuries were sustained in the accident. Your health and well-being are our top priority, and we want to ensure you receive proper compensation for any medical expenses and pain and suffering.'
  : 'Fortunately, no injuries were reported in the accident. However, you may still be entitled to compensation for property damage and other related expenses.';

let solDate = '';
if (extracted.accident_date) {
    let d = new Date(extracted.accident_date);
    d.setFullYear(d.getFullYear() + 8);
    solDate = d.toISOString().split('T')[0];
}

return {
  json: {
    client_first_name: extracted.client_first_name || '',
    client_last_name: extracted.client_last_name || '',
    client_full_name: ${extracted.client_first_name || ''} .trim(),
    defendant_name: ${extracted.defendant_first_name || ''} .trim(),
    accident_date_formatted: extracted.accident_date || '',
    accident_location: extracted.accident_location || '',
    client_plate: extracted.client_plate || '',
    client_pronoun: extracted.client_pronoun || 'they',
    sol_date: solDate,
    has_injuries: extracted.has_injuries || false,
    num_injured: extracted.num_injured || 0,
    booking_link: bookingLink,
    consultation_type: consultationType,
    accident_summary: accidentSummary,
    _raw_extraction: extracted
  }
};

